def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        if n % 2 == 0 and n != 2:
            primes_cache[n] = False
            return False
        for x in range(3, int(n**0.5) + 1, 2):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def prime_factors(n):
        factors = set()
        while n % 2 == 0:
            factors.add(2)
            n //= 2
        f = 3
        while f * f <= n:
            while n % f == 0:
                factors.add(f)
                n //= f
            f += 2
        if n > 1:
            factors.add(n)
        return factors
    def complex_series(x, limit):
        total = 0
        sign = 1
        for i in range(1, limit+1):
            total += sign * (x**i) / (np.math.factorial(i) + 1)
            sign *= -1
            if i % 3 == 0:
                total += np.sin(x*i) * i**0.5
        return total
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else -1000
            continue
        ratio = item / cap
        score = 0
        pfactors = prime_factors(int(cap))
        if ratio < 0.1:
            for a in range(1, 10):
                wave = np.sin(cap * a + item * 2)
                decay = np.exp(-a * ratio * 6)
                score += wave * decay * (30 / (a + 2))
            prime_bonus = sum([pf ** 1.1 for pf in pfactors if is_prime(pf)])
            score += prime_bonus * 1.5
            if cap % 7 == 0:
                score *= 1.15
        elif 0.1 <= ratio < 0.3:
            base = np.cos(ratio * np.pi * 6) * 25
            series_sum = complex_series(ratio, 7)
            score += base + series_sum * 12
            for d in [5,8,12]:
                if cap % d == 0:
                    score += d * 0.7
            if (cap + int(item)) % 4 == 0:
                score *= 1.12
        elif 0.3 <= ratio <= 0.6:
            sine_comp = np.sin(ratio * np.pi * 7) * 18
            factorial_comp = 0
            for e in range(1, 10):
                factorial_comp += ((-1) ** e) * ratio ** e / np.math.factorial(e)
            score += sine_comp + factorial_comp * 12
            for g in range(2, int(min(15, cap))):
                if cap % g == 0 and g % 5 == 2:
                    score += np.sqrt(g) * 3
            if int(cap) % 9 == 0:
                score *= 0.85
        elif 0.6 < ratio <= 1.0:
            logistic = 40 / (1 + np.exp(-20 * (ratio - 0.75)))
            score += logistic
            for h in range(2, 15):
                if is_prime(h) and h % 4 == 3:
                    score += h * 1.1
            if ratio > 0.95:
                score += (1 - ratio) * 80
            if cap % 6 == 0 and ratio < 0.97:
                score *= 1.3
        elif 1.0 < ratio < 2.0:
            penalty = 0
            segment = max(1, int(cap // 4))
            for i in range(1, segment + 2):
                if cap % i == 0:
                    penalty += i ** 2.1
            fract_ratio = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract_ratio * j * 1000) % 11
                penalty += (mod_val / 11) * 7
            score += penalty / (segment + 3)
            score += (ratio - 1) * (-65)
            if cap % 13 == 0:
                score *= 0.88
            if cap % 17 == 0:
                score += 18
        else:
            complex_total = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_total += np.log1p(k) * 4.5
                    else:
                        complex_total += np.sqrt(k) * 3.2
            fract_part = ratio - int(ratio)
            for m in range(1, 12):
                complex_total += np.sin(fract_part * m * np.pi * 1.1) * 2.5
            score += complex_total
            score += (ratio - 3) * 75
            if ratio > 5:
                for n in range(1, int(cap // 2) + 1):
                    if n % 11 == 0:
                        score += np.cos(n) * 5
        if int(cap) % 7 == 0 and ratio < 2.0:
            score *= 1.1
        if int(cap) % 15 == 0 and ratio > 0.6:
            score *= 0.65
        if ratio > 4 and int(cap) % 11 == 0:
            score += 25
        if int(cap) % 16 == 0:
            score *= 0.75
        if int(cap) % 18 == 0 and ratio > 1:
            score *= 1.05
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 350)
    return priorities
